package p2026_03_19;

public class Oper11 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=10, b=10;
		
		System.out.println("a="+a++); //a=10
		System.out.println("a="+a); //a=11
		System.out.println("b="+(++b));//b=11
		System.out.println("b="+b);//b=11
	}

}
